1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	}
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const BLOCK_SIZE = 3;
26	const BLOCK_PREMIUM = 60;
27	
28	function countByType(items: QuoteItem[]): Map<string, number> {
29	  const counts = new Map<string, number>();
30	  for (const item of items) {
31	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
32	  }
33	  return counts;
34	}
35	
36	function priceGroup(type: string, count: number): number {
37	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
38	}
39	
40	function basePremiumFor(items: QuoteItem[]): number {
41	  const countsByType = countByType(items);
42	
43	  let basePremium = 0;
44	  for (const [type, count] of countsByType) {
45	    basePremium += priceGroup(type, count);
46	  }
47	  return basePremium;
48	}
49	
50	export function quote(input: QuoteInput): number {
51	  return basePremiumFor(input.items) + PROCESSING_FEE;
52	}
53	
54	export function claim(input: unknown): number {
55	  return undefined as unknown as number;
56	}
