function curseSurchargeFor(items: QuoteItem[]): number {
  let surcharge = 0;
  for (const item of items) {
    if (item.cursed) {
      surcharge += BASE_PREMIUMS[item.type] * 0.5;
    }
  }
  return surcharge;
}

function basePremiumFor(items: QuoteItem[]): number {
  const countsByType = countByType(items);

  let basePremium = 0;
  for (const [type, count] of countsByType) {
    basePremium += priceGroup(type, count);
  }
  return basePremium + curseSurchargeFor(items);
}
